// ─── RA-826: Parse + filter Google Workspace Updates Atom feed ──────────────
// Blogger publishes Atom 1.0 — entries have <entry> blocks, not <item>.

const rssXml = $input.first().json.data || '';

const KEYWORDS = [
  'gemini', 'mcp', 'model context protocol', 'agent', 'notebooklm',
  'scheduled actions', 'scheduled action', 'automation', 'ai features',
  'workspace ai', 'ai assistant', 'vertex ai', 'duet ai'
];

function extractTag(block, tag) {
  // Prefer CDATA content, then plain text, then strip HTML tags
  const cdata = block.match(new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>`));
  if (cdata) return cdata[1].trim();
  const plain = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\/${tag}>`));
  if (!plain) return '';
  return plain[1]
    .replace(/<!\/CDATA[^>]*>/g, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ')
    .trim();
}

function extractAlternateLink(block) {
  // <link rel='alternate' type='text/html' href='https://...'/>
  const m = block.match(/<link[^>]+rel=['"]alternate['"][^>]+href=['"]([^'"]+)['"]/);
  if (m) return m[1];
  // fallback: any link with http
  const m2 = block.match(/<link[^>]+href=['"]([^'"]+http[^'"]+)['"]/);
  return m2 ? m2[1] : '';
}

function extractCategories(block) {
  const matches = [...block.matchAll(/term=['"]([^'"]+)['"](?:[^/]|$)/g)];
  return matches
    .map(m => m[1])
    .filter(t => !t.startsWith('http') && t.length < 80);
}

// Parse Atom <entry> blocks
const entryRegex = /<entry>([\s\S]*?)<\/entry>/g;
const filtered = [];
let m;

while ((m = entryRegex.exec(rssXml)) !== null) {
  const block = m[1];

  const title      = extractTag(block, 'title');
  const summary    = (extractTag(block, 'summary') || extractTag(block, 'content')).slice(0, 600);
  const published  = extractTag(block, 'published') || extractTag(block, 'updated') || '';
  const guid       = extractTag(block, 'id') || '';
  const link       = extractAlternateLink(block);
  const categories = extractCategories(block);

  // Keyword match across title + summary + categories
  const searchText = (title + ' ' + summary + ' ' + categories.join(' ')).toLowerCase();
  const matched    = KEYWORDS.filter(kw => searchText.includes(kw));

  if (matched.length === 0) continue;

  filtered.push({ title, link, pub_date: published, summary, keywords_matched: matched, categories, guid });
}

if (filtered.length === 0) {
  console.log('RA-826: no keyword-matching entries found in this poll cycle');
  return [{ json: { matched: false, count: 0, items: [] } }];
}

// Format combined doc entry for Google Docs append
const batchDate = new Date().toISOString().split('T')[0];
const docLines = [`\n\n## ${batchDate} — ${filtered.length} update(s) from workspaceupdates.googleblog.com\n`];
for (const item of filtered) {
  docLines.push(`### ${item.title}`);
  docLines.push(`📅 ${item.pub_date}`);
  docLines.push(`🔗 ${item.link}`);
  docLines.push(`🏷️  Keywords matched: ${item.keywords_matched.join(', ')}`);
  if (item.categories.length) docLines.push(`📂 Categories: ${item.categories.join(', ')}`);
  docLines.push(`\n${item.summary}\n`);
  docLines.push('---');
}

console.log(`RA-826: ${filtered.length} keyword-matching entries found`);

return [{
  json: {
    matched:  true,
    count:    filtered.length,
    items:    filtered,
    docEntry: docLines.join('\n'),
    batch_date: batchDate,
    source:   'n8n:workspace-rss-monitor',
  }
}];

const res = $input.first().json;
if (!res.ok) {
  throw new Error(`Pi-CEO workspace-intel POST failed: ${JSON.stringify(res)}`);
}
console.log(`✅ RA-826: workspace intel stored | batch_date=${res.batch_date} | stored=${res.stored} | count=${res.count}`);

// ⚠️ NotebookLM has no public API — manual refresh required.
// After this runs, open the Pi-CEO Intel notebook in NotebookLM and click
// "Sync" on the Pi-CEO Workspace Intel Google Doc source to reflect new content.
console.log('📓 NotebookLM manual action required: refresh Pi-CEO Workspace Intel notebook source');

return [{ json: { success: true, ...res } }];
